    'edit-lesson-activity-common-setting': { title: '12. Activity Common Setting', desc: 'Activity Common Setting contains settings that are applied commonly to each Activity, such as Quiz and Discussion. When you select an Activity, the setting options appear in the right panel.', note: 'Before and after changing Activity Common Setting, check the save status and whether the changes appear correctly on the student screen.', sections: ['Common Setting', 'Time Limit'] },
    'edit-lesson-text-properties': { title: '1. Change Text properties', desc: 'When you click a text object in Edit Lesson, a text properties toolbar appears at the top. Use this toolbar to change the font, size, style, color, alignment, and other properties.', note: 'Before and after changing Text properties, check the save status and whether the changes appear correctly on the student screen.', sections: ['Toolbar layout', 'Notes'] },
