    "edit-lesson-add-text-object": { title: "3. Add a Text object", desc: "You can freely add text objects to a slide. Use this when you want to add extra titles, instructions, or supporting explanations outside the text already included in the layout.", note: "Before and after adding a Text object, check the save status and whether it appears correctly on the student screen.", sections: ["How to add a text object","Text types","Edit after adding"] },
    "edit-lesson-add-shape": { title: "4. Add a shape object", desc: "You can freely add shape objects to a slide. LumiTeach provides 12 shapes, including circles, rectangles, triangles, and arrows, and after adding one you can adjust properties such as color, opacity, size, and alignment.", note: "Before and after adding a shape object, check the save status and whether it appears correctly on the student screen.", sections: ["How to add a shape","Available shapes","Change shape properties"] },
