Object.entries(curriculumStorageExploreJaViTranslations).forEach(([language, pages]) => {
  Object.entries(pages).forEach(([key, value]) => {
    if (value.tree) Object.assign(translations[language].manualTree, { [key]: value.tree });
    if (value.article) Object.assign(translations[language].articles, { [key]: value.article });
    if (value.body) Object.assign(translations[language].articleBodies, { [key]: value.body });
  });
});
